const { useState, useEffect, useRef } = React;
const CHAPTERS = [{ "id": 1, "level": "A1", "title": "DER PILOT", "theme": "MECHA / ELEKTRONIK", "focus": { "title": "sein + der/die/das", "en": "German nouns have a gender: der (masc.), die (fem.), das (neuter). Learn every noun WITH its article. 'ist/sind/bin' are forms of 'sein' (to be)." }, "paragraphs": [["Das ist meine Maschine.", "Sie hei\xDFt ERIS-7.", "Sie ist zw\xF6lf Meter gro\xDF und grau."], ["Ich bin der Pilot.", "Ich pr\xFCfe das System.", "Der Reaktor ist hei\xDF.", "Das ist ein Problem."], ["Ein Sensor blinkt rot.", "Der Sensor misst die Temperatur.", "Die Temperatur ist zu hoch."], ["Ich \xF6ffne das Panel.", "Ich sehe die Platine.", "Ein Kabel ist locker.", "Das ist der Fehler."], ["Ich verbinde das Kabel.", "Der Sensor blinkt gr\xFCn.", "Das System ist stabil.", "Die Maschine ist bereit."], ["Die Stadt brennt.", "Der Feind wartet.", "Der Kampf beginnt."]], "questions": [{ "text": "Was ist der Fehler?", "options": [{ "t": "Ein Kabel ist locker.", "ok": true }, { "t": "Der Pilot ist m\xFCde.", "ok": false }, { "t": "Die Maschine ist zu klein.", "ok": false }] }, { "text": "Was misst der Sensor?", "options": [{ "t": "Die Spannung.", "ok": false }, { "t": "Die Temperatur.", "ok": true }, { "t": "Das Licht.", "ok": false }] }] }, { "id": 2, "level": "A1", "title": "DER MORGEN", "theme": "ALLTAG / ROUTINE", "focus": { "title": "Verben im Pr\xE4sens + um \u2026 Uhr", "en": "Present tense endings: ich trinke, er trinkt, wir trinken. Time uses 'um': um sechs Uhr = at six o'clock. Some verbs split: 'aufstehen' \u2192 'Ich stehe auf.'" }, "paragraphs": [["Es ist sechs Uhr.", "Ich stehe auf.", "Der Hangar ist kalt und still."], ["Ich trinke Kaffee.", "Ich esse Brot mit K\xE4se.", "Das Fr\xFChst\xFCck ist einfach."], ["Dann gehe ich zur Maschine.", "ERIS-7 schl\xE4ft.", "Die Lampen sind aus."], ["Ich starte den Computer.", "Das Log ist leer.", "Keine Fehler.", "Gut."], ["Um sieben Uhr kommt der Techniker.", "Er hei\xDFt Bruno.", "Er bringt Werkzeug."], ["Wir arbeiten zusammen.", "Der Tag beginnt."]], "questions": [{ "text": "Wann steht der Pilot auf?", "options": [{ "t": "Um sechs Uhr.", "ok": true }, { "t": "Um sieben Uhr.", "ok": false }, { "t": "Um zw\xF6lf Uhr.", "ok": false }] }, { "text": "Was bringt Bruno?", "options": [{ "t": "Kaffee.", "ok": false }, { "t": "Werkzeug.", "ok": true }, { "t": "Brot.", "ok": false }] }] }, { "id": 3, "level": "A1", "title": "DIE STADT", "theme": "STADT / ESSEN", "focus": { "title": "es gibt + Akkusativ", "en": "'Es gibt' (there is / there are) always takes Akkusativ: Es gibt einen Markt (not 'ein Markt'). Masculine 'ein' \u2192 'einen' in Akkusativ; feminine and neuter don't change." }, "paragraphs": [["Die Stadt hei\xDFt Vesta.", "Sie liegt im Norden.", "Hier gibt es viele Fabriken."], ["Es gibt auch einen Markt.", "Dort kaufe ich Fleisch und Kartoffeln."], ["Zu Hause habe ich eine Hei\xDFluftfritteuse.", "Ich koche das Fleisch zwanzig Minuten.", "Es ist schnell und gut."], ["Am Abend sehe ich die Mauern der Stadt.", "Sie sind hoch und grau.", "Hinter den Mauern liegt die Zone."], ["Niemand geht in die Zone.", "Dort wohnen die Feinde.", "Wir nennen sie: die Geister."]], "questions": [{ "text": "Was kauft der Pilot auf dem Markt?", "options": [{ "t": "Brot und K\xE4se.", "ok": false }, { "t": "Fleisch und Kartoffeln.", "ok": true }, { "t": "Werkzeug.", "ok": false }] }, { "text": "Wer wohnt in der Zone?", "options": [{ "t": "Die Geister.", "ok": true }, { "t": "Die Techniker.", "ok": false }, { "t": "Niemand.", "ok": false }] }] }, { "id": 4, "level": "A1", "title": "DER TECHNIKER", "theme": "WERKSTATT / TECHNIK", "focus": { "title": "Akkusativ: einen / eine / ein", "en": "Direct objects take Akkusativ. Only masculine changes: einen Hammer, einen Stecker. Feminine (eine Zange) and neuter (ein Kabel) stay the same." }, "paragraphs": [["Bruno \xF6ffnet die Maschine.", "Er hat viele Werkzeuge: einen Hammer, eine Zange, einen Schraubenzieher."], ["Er findet ein Problem.", "Zwei Kabel sind alt.", "Ein Stecker ist schwarz.", "Das riecht verbrannt."], ["\xBBWir brauchen neue Teile\xAB, sagt Bruno.", "\xBBOhne Teile fliegt ERIS nicht.\xAB"], ["Ich frage: \xBBWie lange dauert das?\xAB", "Bruno sagt: \xBBZwei Tage.", "Vielleicht drei.\xAB"], ["Zwei Tage sind lang.", "Die Geister warten nicht."]], "questions": [{ "text": "Wie riecht der Stecker?", "options": [{ "t": "Verbrannt.", "ok": true }, { "t": "Neu.", "ok": false }, { "t": "Gut.", "ok": false }] }, { "text": "Wie lange dauert die Reparatur?", "options": [{ "t": "F\xFCnf Minuten.", "ok": false }, { "t": "Zwei Wochen.", "ok": false }, { "t": "Zwei Tage, vielleicht drei.", "ok": true }] }] }, { "id": 5, "level": "A1", "title": "DAS ESSEN", "theme": "IMBISS / BESTELLEN", "focus": { "title": "ohne + Akkusativ, m\xF6chten", "en": "'ohne' (without) always takes Akkusativ: ohne So\xDFe, ohne Zwiebeln. 'M\xF6chten Sie \u2026?' is the polite way to ask 'Would you like \u2026?' \u2014 you will hear it in every shop." }, "paragraphs": [["Am Freitag gehe ich in die Stadt.", "Ich habe Hunger.", "Es gibt einen Imbiss am Markt."], ["Ich sage: \xBBEinen Burger mit H\xE4hnchen, bitte.", "Aber ohne So\xDFe und ohne Zwiebeln.\xAB"], ["Der Mann fragt: \xBBM\xF6chten Sie Pommes?\xAB", "Ich sage: \xBBJa, eine kleine Portion.\xAB"], ["Das Essen kostet acht Euro.", "Ich bezahle und warte f\xFCnf Minuten."], ["Der Burger ist hei\xDF und gut.", "Ohne So\xDFe schmeckt er besser.", "Das ist meine Meinung."]], "questions": [{ "text": "Was bestellt der Pilot?", "options": [{ "t": "Einen Burger ohne So\xDFe und ohne Zwiebeln.", "ok": true }, { "t": "Eine Pizza mit K\xE4se.", "ok": false }, { "t": "Nur Pommes.", "ok": false }] }, { "text": "Was kostet das Essen?", "options": [{ "t": "F\xFCnf Euro.", "ok": false }, { "t": "Acht Euro.", "ok": true }, { "t": "Zw\xF6lf Euro.", "ok": false }] }] }, { "id": 6, "level": "A1", "title": "DER BEFEHL", "theme": "MILIT\xC4R / MODALVERBEN", "focus": { "title": "Modalverben: m\xFCssen, k\xF6nnen, sollen, wollen", "en": "Modal verb sits in position 2, the main verb goes to the END as infinitive: 'Du musst heute fliegen.' Negation: 'Du musst nicht k\xE4mpfen' = you don't have to fight." }, "paragraphs": [["Um Mitternacht klingelt das Telefon.", "Der Kommandant spricht: \xBBDie Geister kommen.", "Du musst fliegen.\xAB"], ["Ich sage: \xBBDie Maschine ist nicht fertig.", "Wir k\xF6nnen nicht k\xE4mpfen.\xAB"], ["\xBBDu musst nicht k\xE4mpfen\xAB, sagt er.", "\xBBDu sollst nur beobachten.", "Flieg hoch und bleib ruhig.\xAB"], ["Bruno arbeitet schnell.", "Nach einer Stunde sagt er: \xBBDie Kabel sind neu.", "Du kannst starten.\xAB"], ["Ich will nicht fliegen.", "Aber ich muss.", "Das ist der Befehl."]], "questions": [{ "text": "Was soll der Pilot machen?", "options": [{ "t": "Er soll k\xE4mpfen.", "ok": false }, { "t": "Er soll nur beobachten.", "ok": true }, { "t": "Er soll schlafen.", "ok": false }] }, { "text": "Wann klingelt das Telefon?", "options": [{ "t": "Um Mitternacht.", "ok": true }, { "t": "Am Morgen.", "ok": false }, { "t": "Um sieben Uhr.", "ok": false }] }] }, { "id": 7, "level": "A1", "title": "DIE NACHT", "theme": "MISSION / PERFEKT", "focus": { "title": "Perfekt: haben oder sein?", "en": "Past tense in speech = Perfekt: haben/sein + participle at the end. Movement/change verbs take SEIN: ich bin geflogen. Most others take HABEN: ich habe gesehen." }, "paragraphs": [["Ich bin drei Stunden geflogen.", "Die Zone war dunkel und still."], ["Dann habe ich ein Licht gesehen.", "Es war kein Geist.", "Es war ein Mensch \u2014 ein M\xE4dchen mit einer Lampe."], ["Ich habe sie fotografiert und bin zur\xFCckgeflogen.", "Der Kommandant hat das Foto lange angesehen."], ["\xBBDas ist unm\xF6glich\xAB, hat er gesagt.", "\xBBIn der Zone wohnen keine Menschen.\xAB"], ["Aber das Foto l\xFCgt nicht.", "Jemand lebt dort.", "Und wir wissen nicht, wer."]], "questions": [{ "text": "Was hat der Pilot in der Zone gesehen?", "options": [{ "t": "Einen Geist.", "ok": false }, { "t": "Ein M\xE4dchen mit einer Lampe.", "ok": true }, { "t": "Nichts.", "ok": false }] }, { "text": "Wie lange ist der Pilot geflogen?", "options": [{ "t": "Eine Stunde.", "ok": false }, { "t": "Drei Stunden.", "ok": true }, { "t": "Die ganze Nacht.", "ok": false }] }] }, { "id": 8, "level": "A1", "title": "DER SUPERMARKT", "theme": "EINKAUFEN / ZAHLEN", "focus": { "title": "Akkusativ beim Einkaufen", "en": "Shopping runs on the Akkusativ: Ich brauche einen Apfel, eine Zwiebel, ein Brot. Prices use 'kostet/kosten'. 'Wie viel kostet das?' opens every purchase." }, "paragraphs": [["Heute kaufe ich ein.", "Der Supermarkt ist gro\xDF und hell.", "Ich habe eine Liste."], ["Ich brauche Brot, Milch und Eier.", "Ich nehme auch einen Apfel und eine Zwiebel.", "Die Zwiebel ist f\xFCr Bruno."], ["Das Brot kostet zwei Euro.", "Die Milch kostet einen Euro.", "Zehn Eier kosten drei Euro."], ["An der Kasse wartet eine Frau.", "Ich zahle neun Euro und zwanzig Cent.", "Das ist nicht billig."], ["Zu Hause packe ich alles aus.", "Ein Ei ist kaputt.", "Kein Problem \u2014 ich koche es heute."]], "questions": [{ "text": "F\xFCr wen ist die Zwiebel?", "options": [{ "t": "F\xFCr Bruno.", "ok": true }, { "t": "F\xFCr die Frau an der Kasse.", "ok": false }, { "t": "F\xFCr den Kommandanten.", "ok": false }] }, { "text": "Wie viel kosten zehn Eier?", "options": [{ "t": "Zwei Euro.", "ok": false }, { "t": "Drei Euro.", "ok": true }, { "t": "Neun Euro.", "ok": false }] }] }, { "id": 9, "level": "A1", "title": "DIE WOCHE", "theme": "ALLTAG / WOCHENTAGE", "focus": { "title": "Wochentage mit am", "en": "Days take 'am': am Montag, am Dienstag. Routines live in the present tense. 'jeden Tag' = every day, 'einmal pro Woche' = once a week." }, "paragraphs": [["Meine Woche hat einen Plan.", "Am Montag pr\xFCfe ich die Systeme.", "Das dauert den ganzen Tag."], ["Am Dienstag und am Mittwoch arbeite ich mit Bruno.", "Wir reparieren und testen.", "Am Donnerstag schreibe ich Berichte."], ["Am Freitag gehe ich zum Markt.", "Am Samstag fliege ich eine Runde.", "Das ist Training, keine Mission."], ["Am Sonntag arbeite ich nicht.", "Ich schlafe lange und koche gut.", "Einmal pro Woche ist das wichtig."], ["Jeden Tag lerne ich Deutsch.", "Drei\xDFig Minuten, nicht mehr.", "Aber jeden Tag."]], "questions": [{ "text": "Was macht der Pilot am Donnerstag?", "options": [{ "t": "Er schreibt Berichte.", "ok": true }, { "t": "Er geht zum Markt.", "ok": false }, { "t": "Er schl\xE4ft lange.", "ok": false }] }, { "text": "Wie lange lernt er jeden Tag Deutsch?", "options": [{ "t": "Den ganzen Tag.", "ok": false }, { "t": "Drei\xDFig Minuten.", "ok": true }, { "t": "Eine Woche.", "ok": false }] }] }, { "id": 10, "level": "A1", "title": "DAS WETTER", "theme": "WETTER / MIKROKLIMA", "focus": { "title": "Wetter-S\xE4tze mit es", "en": "Weather uses 'es': Es regnet, es schneit, es ist kalt. Temperatures: 'Es sind zehn Grad.' A pilot reads the sky like a sensor." }, "paragraphs": [["Heute ist das Wetter schlecht.", "Es regnet seit dem Morgen.", "Der Himmel ist grau."], ["Es sind nur acht Grad.", "Der Wind ist stark.", "Bei Wind fliege ich nicht gern."], ["Im Hangar ist es trocken.", "Die Luft ist hier immer gleich: einundzwanzig Grad.", "Das System macht das automatisch."], ["Bruno sagt: \u201EDrau\xDFen Wetter, drinnen Klima.\u201C", "Er hat recht.", "Drau\xDFen entscheidet der Himmel, drinnen entscheiden wir."], ["Morgen kommt die Sonne.", "Dann teste ich die Maschine.", "Gutes Wetter, guter Tag."]], "questions": [{ "text": "Wie ist die Luft im Hangar?", "options": [{ "t": "Immer gleich: 21 Grad.", "ok": true }, { "t": "Kalt und nass.", "ok": false }, { "t": "Acht Grad.", "ok": false }] }, { "text": "Was sagt Bruno?", "options": [{ "t": "\u201EDrau\xDFen Wetter, drinnen Klima.\u201C", "ok": true }, { "t": "\u201EBei Wind fliegen wir.\u201C", "ok": false }, { "t": "\u201EDer Himmel ist blau.\u201C", "ok": false }] }] }, { "id": 11, "level": "A1", "title": "BRUNO KOCHT", "theme": "KOCHEN / HEISSLUFT", "focus": { "title": "Imperativ in der K\xFCche", "en": "Recipes speak in the imperative: Schneide! Gib! Warte! The du-form drops the ending: du schneidest \u2192 Schneide!" }, "paragraphs": [["Bruno kocht heute.", "Er hat auch eine Hei\xDFluftfritteuse.", "\u201EDas ist auch nur eine Maschine\u201C, sagt er."], ["Das Rezept ist einfach.", "Schneide die Kartoffeln!", "Gib ein wenig \xD6l dazu!"], ["Zwanzig Minuten bei zweihundert Grad.", "Die Maschine macht die Arbeit.", "Wir trinken Kaffee und warten."], ["Dann sind die Kartoffeln fertig.", "Sie sind hei\xDF und knusprig.", "Bruno gibt Salz dazu."], ["Wir essen im Hangar.", "ERIS-7 steht neben uns.", "Sie isst nichts. Sie trinkt nur Strom."]], "questions": [{ "text": "Wie lange kochen die Kartoffeln?", "options": [{ "t": "Zwanzig Minuten bei 200 Grad.", "ok": true }, { "t": "Zwei Stunden.", "ok": false }, { "t": "F\xFCnf Minuten bei 100 Grad.", "ok": false }] }, { "text": "Was \u201Etrinkt\u201C ERIS-7?", "options": [{ "t": "Kaffee.", "ok": false }, { "t": "\xD6l.", "ok": false }, { "t": "Nur Strom.", "ok": true }] }] }, { "id": 12, "level": "A1", "title": "DER BUS", "theme": "TRANSPORT / UHRZEIT", "focus": { "title": "Uhrzeiten im Verkehr", "en": "Timetables use the clock: um 7:15 = um Viertel nach sieben. 'Der Bus f\xE4hrt' \u2014 vehicles use 'fahren', people 'nehmen den Bus'." }, "paragraphs": [["Der Hangar liegt weit von der Stadt.", "Ich nehme den Bus.", "Der Bus f\xE4hrt um Viertel nach sieben."], ["Ich warte an der Haltestelle.", "Der Bus kommt p\xFCnktlich.", "Das ist selten und sch\xF6n."], ["Die Fahrt dauert zwanzig Minuten.", "Ich sehe die Mauern, den Fluss und die Fabriken.", "Vesta wacht langsam auf."], ["Eine alte Frau fragt: \u201EF\xE4hrt der Bus zum Markt?\u201C", "Ich sage: \u201EJa, bis zum Markt und dann zum Amt.\u201C", "Sie lacht: \u201EZum Amt will niemand.\u201C"], ["Um acht Uhr bin ich in der Stadt.", "Der Tag beginnt.", "Ohne Maschine, nur mit Beinen."]], "questions": [{ "text": "Wann f\xE4hrt der Bus?", "options": [{ "t": "Um Viertel nach sieben.", "ok": true }, { "t": "Um halb acht.", "ok": false }, { "t": "Um acht Uhr.", "ok": false }] }, { "text": "Was sagt die alte Frau?", "options": [{ "t": "\u201EZum Amt will niemand.\u201C", "ok": true }, { "t": "\u201EDer Bus ist zu langsam.\u201C", "ok": false }, { "t": "\u201EIch fahre zum Hangar.\u201C", "ok": false }] }] }, { "id": 13, "level": "A1", "title": "DAS M\xC4DCHEN", "theme": "STORY / FRAGEN", "focus": { "title": "Fragen stellen", "en": "W-questions put the verb second: Wer bist du? Wo wohnst du? Yes/no questions start with the verb: Kommst du aus der Zone?" }, "paragraphs": [["Ich sehe das M\xE4dchen wieder.", "Sie steht am Fluss.", "Sie ist vielleicht zehn Jahre alt."], ["Ich frage: \u201EWer bist du?\u201C", "Sie antwortet nicht.", "Sie sieht meine Jacke an \u2014 die Jacke vom Piloten."], ["\u201EWo wohnst du?\u201C, frage ich.", "\u201EHast du Hunger?\u201C", "Sie nimmt mein Brot, aber sie sagt kein Wort."], ["Dann fragt sie leise: \u201EFliegst du die gro\xDFe Maschine?\u201C", "Ich sage: \u201EJa.\u201C", "\u201EGut\u201C, sagt sie. \u201EDann finde meine Familie.\u201C"], ["Sie geht zur Mauer.", "Ich sehe: dort ist ein Loch, klein und dunkel.", "Kein Geist. Nur ein Kind und ein Loch in der Mauer."]], "questions": [{ "text": "Was nimmt das M\xE4dchen?", "options": [{ "t": "Das Brot.", "ok": true }, { "t": "Die Jacke.", "ok": false }, { "t": "Die Maschine.", "ok": false }] }, { "text": "Was ist an der Mauer?", "options": [{ "t": "Ein Loch, klein und dunkel.", "ok": true }, { "t": "Ein Geist.", "ok": false }, { "t": "Ein Bus.", "ok": false }] }] }, { "id": 14, "level": "A2", "title": "DIE FESTUNG", "theme": "MITTELALTER / TAKTIK", "focus": { "title": "Adjektive nach sein + aber", "en": "After 'sein' adjectives take no ending: Die Mauern sind alt. 'aber' connects two contrasting ideas without changing word order: alt, aber stark." }, "paragraphs": [["Der Winter kommt.", "Unsere Festung liegt am Fluss.", "Die Mauern sind alt, aber stark."], ["Ich z\xE4hle die Soldaten: vierzig Mann.", "Wir haben wenig Pfeile und wenig Brot."], ["Der Feind hat zweihundert Mann.", "Er hat auch eine Belagerungsmaschine.", "Sie ist aus Holz."], ["Aber wir haben einen Plan.", "Das Tor bleibt offen.", "Der Feind sieht das Tor und l\xE4uft in die Falle."], ["Hinter dem Tor wartet \xD6l.", "Es ist hei\xDF.", "Der Hauptmann hebt die Hand.", "Wir warten."]], "questions": [{ "text": "Was ist der Plan?", "options": [{ "t": "Wir verlassen die Festung.", "ok": false }, { "t": "Das offene Tor ist eine Falle.", "ok": true }, { "t": "Wir kaufen mehr Brot.", "ok": false }] }, { "text": "Wie viele Soldaten hat die Festung?", "options": [{ "t": "Vierzig.", "ok": true }, { "t": "Zweihundert.", "ok": false }, { "t": "Zehn.", "ok": false }] }] }, { "id": 15, "level": "A2", "title": "DER BOTE", "theme": "MITTELALTER / PR\xC4TERITUM", "focus": { "title": "Pr\xE4teritum (war, hatte) + weil", "en": "In stories, 'sein' and 'haben' use simple past: war, hatte. 'weil' (because) kicks the verb to the END of the clause: \u2026, weil dort Krieg ist." }, "paragraphs": [["Vor der Schlacht kam ein Bote.", "Er war jung und hatte Angst."], ["Er brachte einen Brief vom K\xF6nig.", "Der Hauptmann las den Brief langsam."], ["\xBBEs gibt keine Hilfe\xAB, sagte er.", "\xBBDer K\xF6nig braucht seine Soldaten im S\xFCden, weil dort Krieg ist.\xAB"], ["Die M\xE4nner waren still.", "Vierzig gegen zweihundert \u2014 ohne Hilfe."], ["Aber der Hauptmann l\xE4chelte.", "\xBBGut\xAB, sagte er.", "\xBBDann gewinnen wir allein.\xAB"]], "questions": [{ "text": "Warum gibt es keine Hilfe?", "options": [{ "t": "Weil der K\xF6nig die Soldaten im S\xFCden braucht.", "ok": true }, { "t": "Weil der Bote den Brief verloren hat.", "ok": false }, { "t": "Weil der Winter kommt.", "ok": false }] }, { "text": "Wie war der Bote?", "options": [{ "t": "Alt und stark.", "ok": false }, { "t": "Jung, und er hatte Angst.", "ok": true }, { "t": "Laut und froh.", "ok": false }] }] }, { "id": 16, "level": "A2", "title": "DAS AMT", "theme": "B\xDCROKRATIE / FORMULARE", "focus": { "title": "Sie-Imperativ + Dativ (mir, Ihnen)", "en": "Polite commands: 'F\xFCllen Sie das aus.' (verb first + Sie). 'geben' takes Dativ for the receiver: Sie gibt MIR ein Formular. You will hear 'Haben Sie einen Termin?' in every German office." }, "paragraphs": [["Zur\xFCck in Vesta: Ich brauche eine neue Lizenz f\xFCr die Maschine.", "Ohne Lizenz darf ich nicht fliegen."], ["Ich gehe zum Amt.", "Die Frau am Schalter gibt mir ein Formular und sagt: \xBBF\xFCllen Sie das bitte aus.\xAB"], ["Das Formular hat vier Seiten.", "Ich brauche meinen Pass, eine Bescheinigung und ein Foto."], ["\xBBHaben Sie einen Termin?\xAB, fragt die Frau.", "Ich sage: \xBBNein.", "Kann ich heute einen Termin machen?\xAB"], ["\xBBDer n\xE4chste Termin ist in drei Wochen\xAB, sagt sie.", "Ich bleibe ruhig.", "Das Amt ist st\xE4rker als jeder Feind."]], "questions": [{ "text": "Was braucht der Pilot f\xFCr das Formular?", "options": [{ "t": "Nur ein Foto.", "ok": false }, { "t": "Pass, Bescheinigung und Foto.", "ok": true }, { "t": "Geld und Werkzeug.", "ok": false }] }, { "text": "Wann ist der n\xE4chste Termin?", "options": [{ "t": "Heute.", "ok": false }, { "t": "In drei Wochen.", "ok": true }, { "t": "Morgen.", "ok": false }] }] }, { "id": 17, "level": "A2", "title": "DIE WERKSTATT", "theme": "ELEKTRONIK / VERGLEICHE", "focus": { "title": "Komparativ + als", "en": "Comparative = adjective + er: stark \u2192 st\xE4rker, alt \u2192 \xE4lter (often with umlaut). Compare with 'als': besser als, l\xE4nger als. 'deshalb' (therefore) links cause and result." }, "paragraphs": [["Bruno zeigt mir die Werkstatt.", "Auf dem Tisch liegen Widerst\xE4nde, Kondensatoren und eine gro\xDFe Platine."], ["\xBBDieser Widerstand ist zu schwach\xAB, sagt er.", "\xBBWir brauchen einen st\xE4rkeren.", "Und dieser Kondensator ist \xE4lter als du.\xAB"], ["Er misst die Spannung: zw\xF6lf Volt.", "Der Strom ist zu hoch, deshalb wird das Kabel warm."], ["Ich lerne viel: Ein kurzes Kabel ist besser als ein langes.", "Ein kaltes System lebt l\xE4nger als ein hei\xDFes."], ["\xBBElektronik ist einfach\xAB, sagt Bruno.", "\xBBMenschen sind komplizierter.\xAB"]], "questions": [{ "text": "Warum wird das Kabel warm?", "options": [{ "t": "Weil der Strom zu hoch ist.", "ok": true }, { "t": "Weil die Sonne scheint.", "ok": false }, { "t": "Weil das Kabel neu ist.", "ok": false }] }, { "text": "Was ist besser?", "options": [{ "t": "Ein langes Kabel.", "ok": false }, { "t": "Ein kurzes Kabel.", "ok": true }, { "t": "Ein warmes Kabel.", "ok": false }] }] }, { "id": 18, "level": "A2", "title": "DAS LOGBUCH", "theme": "MIKROKLIMA / TECHNIK", "focus": { "title": "Zahlen + Messwerte lesen", "en": "Technical German states values with 'liegt bei / betr\xE4gt': Die Luftfeuchtigkeit liegt bei 82 Prozent. 'kein/keine' negates nouns: keinen Strom = no power." }, "paragraphs": [["Station M-5, Tag 112.", "Ich kontrolliere das Klimasystem jeden Morgen."], ["Heute zeigt das Log einen Fehler: Die Luftfeuchtigkeit im Labor liegt bei 82 Prozent.", "Normal sind 45 Prozent."], ["Ein L\xFCfter l\xE4uft nicht.", "Der Motor bekommt keinen Strom.", "Ich messe die Spannung: null Volt."], ["Die Sicherung ist kaputt.", "Ich habe eine neue Sicherung.", "Nach zehn Minuten l\xE4uft der L\xFCfter wieder."], ["Die Werte sinken langsam.", "Das System ist wieder normal.", "Ich schreibe alles ins Logbuch."]], "questions": [{ "text": "Warum l\xE4uft der L\xFCfter nicht?", "options": [{ "t": "Das Labor ist zu kalt.", "ok": false }, { "t": "Das Logbuch fehlt.", "ok": false }, { "t": "Die Sicherung ist kaputt.", "ok": true }] }, { "text": "Wie hoch ist die Luftfeuchtigkeit heute?", "options": [{ "t": "45 Prozent.", "ok": false }, { "t": "82 Prozent.", "ok": true }, { "t": "112 Prozent.", "ok": false }] }] }, { "id": 19, "level": "A2", "title": "DER VERDACHT", "theme": "STORY / WENN-S\xC4TZE", "focus": { "title": "wenn-S\xE4tze", "en": "'wenn' (if/when) sends the verb to the end: Wenn ich es melde, schickt er Soldaten. If the wenn-clause comes first, the main clause starts with the verb." }, "paragraphs": [["Ich habe das M\xE4dchen wieder gesehen \u2014 diesmal am Markt in Vesta.", "Wenn das stimmt, kann sie durch die Mauer gehen."], ["Ich bin ihr gefolgt.", "Sie hat Brot gekauft und hat mit niemandem gesprochen."], ["An der Mauer ist sie stehen geblieben.", "Dann war sie weg.", "Einfach weg."], ["Ich habe dem Kommandanten nichts gesagt.", "Wenn ich es melde, schickt er Soldaten."], ["Vielleicht ist sie kein Geist.", "Vielleicht ist sie der Schl\xFCssel."]], "questions": [{ "text": "Wo hat der Pilot das M\xE4dchen gesehen?", "options": [{ "t": "In der Zone.", "ok": false }, { "t": "Am Markt in Vesta.", "ok": true }, { "t": "Im Hangar.", "ok": false }] }, { "text": "Warum sagt der Pilot dem Kommandanten nichts?", "options": [{ "t": "Weil der Kommandant sonst Soldaten schickt.", "ok": true }, { "t": "Weil er das M\xE4dchen nicht gesehen hat.", "ok": false }, { "t": "Weil das Telefon kaputt ist.", "ok": false }] }] }, { "id": 20, "level": "A2", "title": "DIE PAPIERE", "theme": "B\xDCROKRATIE / DATIV", "focus": { "title": "Dativ: geben, helfen, geh\xF6ren", "en": "Documents flow in the Dativ: Ich gebe dem Amt die Kopie. Das Papier geh\xF6rt dem M\xE4dchen. helfen + Dativ: Ich helfe ihr." }, "paragraphs": [["Das M\xE4dchen hei\xDFt Kara.", "Sie hat keine Papiere.", "Ohne Papiere gibt es kein Brot vom Amt, keinen Arzt, keine Schule."], ["Ich gehe zum B\xFCrgerb\xFCro und frage der Frau am Schalter viele Fragen.", "Korrektur: Ich stelle der Frau viele Fragen.", "Deutsch ist pr\xE4zise \u2014 man stellt Fragen, man fragt Personen."], ["Die Frau gibt mir eine Liste.", "F\xFCr einen Ausweis braucht man: ein Formular, zwei Fotos und einen Nachweis.", "\u201EWelchen Nachweis?\u201C, frage ich. \u201EIrgendeinen\u201C, sagt sie."], ["Ich helfe Kara mit dem Formular.", "Name: Kara. Geburtsort: unbekannt. Wohnort: unbekannt.", "Das Formular mag das Wort \u201Eunbekannt\u201C nicht."], ["Aber ich gebe nicht auf.", "Dem M\xE4dchen geh\xF6rt eine Zukunft.", "Und die Zukunft beginnt mit einem St\xFCck Papier."]], "questions": [{ "text": "Was braucht man f\xFCr einen Ausweis?", "options": [{ "t": "Ein Formular, zwei Fotos und einen Nachweis.", "ok": true }, { "t": "Nur ein Foto.", "ok": false }, { "t": "Einen Arzt und eine Schule.", "ok": false }] }, { "text": "Welches Wort mag das Formular nicht?", "options": [{ "t": "\u201Eunbekannt\u201C", "ok": true }, { "t": "\u201EKara\u201C", "ok": false }, { "t": "\u201EZukunft\u201C", "ok": false }] }] }, { "id": 21, "level": "A2", "title": "DIE NACHTSCHICHT", "theme": "WERKSTATT / PERFEKT", "focus": { "title": "Perfekt erz\xE4hlt die Nacht", "en": "Spoken past = Perfekt: Wir haben gearbeitet. Ich bin geblieben. Remember: bleiben takes sein \u2014 ich bin geblieben." }, "paragraphs": [["Gestern haben wir eine Nachtschicht gemacht.", "Ein Transport ist am Abend gekommen: neue Teile f\xFCr ERIS-7.", "Wir haben bis drei Uhr gearbeitet."], ["Bruno hat die alten Stecker ausgebaut.", "Ich habe die neuen Kabel verlegt.", "Um Mitternacht haben wir Pause gemacht und kalte Kartoffeln gegessen."], ["Dann ist etwas passiert.", "Ein Sensor hat pl\xF6tzlich rot geblinkt \u2014 ohne Grund.", "Wir haben eine Stunde gesucht und nichts gefunden."], ["Bruno ist ruhig geblieben.", "\u201EEin Geist im System\u201C, hat er gelacht.", "Dann hat er den Sensor einfach getauscht. Der Geist ist verschwunden."], ["Um vier Uhr bin ich ins Bett gegangen.", "Ich habe von blinkenden Lichtern getr\xE4umt.", "Techniker tr\xE4umen selten von Schafen."]], "questions": [{ "text": "Bis wann haben sie gearbeitet?", "options": [{ "t": "Bis drei Uhr.", "ok": true }, { "t": "Bis Mitternacht.", "ok": false }, { "t": "Bis zum Morgen um acht.", "ok": false }] }, { "text": "Wie hat Bruno den \u201EGeist\u201C vertrieben?", "options": [{ "t": "Er hat den Sensor getauscht.", "ok": true }, { "t": "Er hat laut gerufen.", "ok": false }, { "t": "Er hat das Licht ausgemacht.", "ok": false }] }] }, { "id": 22, "level": "A2", "title": "DER MARKTTAG", "theme": "MARKT / VERGLEICHE", "focus": { "title": "Komparativ beim Handeln", "en": "Bargaining is comparing: billiger, frischer, besser als. Superlative for the final blow: der beste Preis, am frischesten." }, "paragraphs": [["Samstag ist Markttag in Vesta.", "Der Markt ist lauter und voller als sonst.", "Ich suche Gem\xFCse f\xFCr die Woche."], ["Ein H\xE4ndler ruft: \u201EDie frischesten Tomaten der Stadt!\u201C", "Der zweite H\xE4ndler ruft: \u201EMeine sind frischer und billiger!\u201C", "Der dritte sagt nichts. Er hat die l\xE4ngste Schlange."], ["Ich frage den dritten: \u201EWarum sind Ihre Tomaten besser?\u201C", "Er sagt: \u201ESie sind nicht besser. Aber ich wiege ehrlich.\u201C", "Ehrlichkeit ist das beste Marketing."], ["Ich kaufe zwei Kilo Tomaten, einen Sack Kartoffeln und Zwiebeln.", "Alles zusammen kostet weniger als im Supermarkt.", "Aber es dauert l\xE4nger. Zeit gegen Geld \u2014 der \xE4lteste Handel der Welt."], ["Auf dem R\xFCckweg sehe ich Kara am Brotstand.", "Der B\xE4cker gibt ihr ein Brot und will kein Geld.", "Vesta ist h\xE4rter als Stein und weicher als Brot. Beides gleichzeitig."]], "questions": [{ "text": "Warum hat der dritte H\xE4ndler die l\xE4ngste Schlange?", "options": [{ "t": "Er wiegt ehrlich.", "ok": true }, { "t": "Er ruft am lautesten.", "ok": false }, { "t": "Seine Tomaten sind die billigsten.", "ok": false }] }, { "text": "Was macht der B\xE4cker?", "options": [{ "t": "Er gibt Kara ein Brot und will kein Geld.", "ok": true }, { "t": "Er verkauft Kara Tomaten.", "ok": false }, { "t": "Er ruft die Polizei.", "ok": false }] }] }, { "id": 23, "level": "A2", "title": "DER BRIEF AN BRUNO", "theme": "BRIEF / NEBENS\xC4TZE", "focus": { "title": "weil und dass im Brief", "en": "Personal letters glue thoughts with weil and dass \u2014 verb goes to the end: Ich schreibe dir, weil ich eine Idee habe. Ich glaube, dass es funktioniert." }, "paragraphs": [["Bruno ist eine Woche bei seiner Schwester im S\xFCden.", "Ich schreibe ihm einen Brief, weil das Telefon dort nicht funktioniert.", "Ein Brief auf Papier \u2014 wie im Mittelalter."], ["\u201ELieber Bruno, ich hoffe, dass es dir gut geht.", "Hier ist alles ruhig, weil die Maschine endlich stabil l\xE4uft.", "Sogar der Reaktor ist brav.\u201C"], ["\u201EIch habe eine Idee: Wir bauen einen zweiten Sensor an die Mauer, weil dort die Temperatur immer springt.", "Ich glaube, dass das Loch in der Mauer die Ursache ist.", "Kalte Luft kommt durch \u2014 und vielleicht nicht nur Luft.\u201C"], ["\u201EKara fragt jeden Tag, wann du zur\xFCckkommst.", "Sie sagt, dass deine Kartoffeln die besten sind.", "Ich sage ihr, dass du auch nur eine Maschine bedienst.\u201C"], ["\u201EKomm gesund zur\xFCck. Dein Pilot.\u201C", "Ich klebe eine Briefmarke auf den Umschlag.", "Manche Nachrichten brauchen Gewicht."]], "questions": [{ "text": "Warum schreibt der Pilot einen Brief?", "options": [{ "t": "Weil das Telefon im S\xFCden nicht funktioniert.", "ok": true }, { "t": "Weil Briefe billiger sind.", "ok": false }, { "t": "Weil Bruno nicht lesen kann.", "ok": false }] }, { "text": "Was glaubt der Pilot \xFCber die Mauer?", "options": [{ "t": "Dass das Loch die Ursache f\xFCr die Temperatur ist.", "ok": true }, { "t": "Dass die Mauer zu hoch ist.", "ok": false }, { "t": "Dass dort ein Geist wohnt.", "ok": false }] }] }, { "id": 24, "level": "A2", "title": "DIE ALTE KARTE", "theme": "MITTELALTER / PR\xC4TERITUM", "focus": { "title": "war, hatte, fand", "en": "Old stories run in Pr\xE4teritum: war, hatte, gab, fand, stand. For A2 the big four carry you: sein\u2192war, haben\u2192hatte, geben\u2192gab, finden\u2192fand." }, "paragraphs": [["Im Archiv der Stadt fand ich eine alte Karte.", "Sie war von der Festung am Fluss \u2014 unserer Festung aus den alten Geschichten.", "Die Karte hatte braune Flecken und einen Riss."], ["Auf der Karte gab es etwas Interessantes: einen Tunnel.", "Er begann im Keller der Festung und endete am Fluss.", "So brachte man Wasser und Brot in die Festung, als der Feind vor den Mauern stand."], ["Der Kapit\xE4n von damals war klug.", "Er hatte nicht nur hei\xDFes \xD6l.", "Er hatte auch einen Plan B unter der Erde."], ["Ich zeigte die Karte dem Archivar.", "Er sagte: \u201EDie Festung stand genau dort, wo heute die Zone ist.\u201C", "Ich wurde still."], ["Ein alter Tunnel unter der Zone.", "Vielleicht war Karas Loch in der Mauer kein Zufall.", "Geschichte schl\xE4ft. Aber sie stirbt nicht."]], "questions": [{ "text": "Was zeigte die alte Karte?", "options": [{ "t": "Einen Tunnel vom Keller zum Fluss.", "ok": true }, { "t": "Einen neuen Supermarkt.", "ok": false }, { "t": "Den Plan der Stadt Vesta.", "ok": false }] }, { "text": "Wo stand die Festung?", "options": [{ "t": "Dort, wo heute die Zone ist.", "ok": true }, { "t": "Im S\xFCden bei der Schwester.", "ok": false }, { "t": "Neben dem Hangar.", "ok": false }] }] }, { "id": 25, "level": "A2", "title": "DER UMZUG", "theme": "WOHNEN / WECHSELPR\xC4P.", "focus": { "title": "Wohin? Akkusativ. Wo? Dativ.", "en": "Moving is a Wechselpr\xE4position drill: Ich stelle den Tisch an die Wand (wohin? Akk). Der Tisch steht an der Wand (wo? Dat)." }, "paragraphs": [["Ich ziehe um: aus dem Hangar in eine kleine Wohnung in der Stadt.", "Ein Pilot braucht auch ein Zuhause ohne Reaktor.", "Bruno hilft mir mit seinem alten Transporter."], ["Wir tragen den Tisch in die K\xFCche und stellen ihn an die Wand.", "Jetzt steht der Tisch an der Wand \u2014 perfekt.", "Das Bett kommt ins Schlafzimmer, der Werkzeugkasten unter das Bett."], ["\u201EWarum liegt der Werkzeugkasten unter dem Bett?\u201C, fragt Bruno.", "\u201EWeil ein Techniker nachts manchmal Ideen hat\u201C, sage ich.", "Er nickt. Das versteht er."], ["An die Wand \xFCber dem Tisch h\xE4nge ich das Foto: ERIS-7 im Morgenlicht.", "Neben das Foto h\xE4nge ich die alte Karte mit dem Tunnel.", "Maschine und Geschichte, Seite an Seite."], ["Am Abend sitzen wir auf dem Boden zwischen den Kisten und essen Pizza.", "\u201EDeine erste Nacht in einem normalen Haus\u201C, sagt Bruno.", "Durch das Fenster sehe ich den Hangar. Er sieht klein aus. Und ein bisschen einsam."]], "questions": [{ "text": "Wohin stellen sie den Tisch?", "options": [{ "t": "An die Wand in der K\xFCche.", "ok": true }, { "t": "Unter das Bett.", "ok": false }, { "t": "In den Hangar.", "ok": false }] }, { "text": "Warum liegt der Werkzeugkasten unter dem Bett?", "options": [{ "t": "Weil ein Techniker nachts manchmal Ideen hat.", "ok": true }, { "t": "Weil kein Platz in der K\xFCche ist.", "ok": false }, { "t": "Weil Bruno das so will.", "ok": false }] }] }, { "id": 26, "level": "B1", "title": "DER BRIEF VOM AMT", "theme": "AMTSDEUTSCH / PASSIV", "focus": { "title": "Passiv + \u201Eist einzureichen\u201C", "en": "Official German loves passive: wurde gepr\xFCft (was checked), wird abgelehnt (will be rejected). 'ist einzureichen' = must be submitted \u2014 a passive obligation you will see in every official letter." }, "paragraphs": [["Ein Brief liegt im Briefkasten.", "Ich \xF6ffne ihn langsam."], ["\xBBSehr geehrter Herr, Ihr Antrag vom 12. M\xE4rz wurde gepr\xFCft.", "Folgende Unterlagen fehlen: eine g\xFCltige Bescheinigung \xFCber die technische Kontrolle der Maschine."], ["Die Bescheinigung ist innerhalb von 14 Tagen einzureichen.", "Andernfalls wird der Antrag abgelehnt."], ["Bitte beachten Sie: Ohne g\xFCltige Lizenz ist der Betrieb der Maschine verboten.", "Bei Fragen wenden Sie sich an das B\xFCrgerb\xFCro, Zimmer 214.\xAB"], ["Ich lese den Brief dreimal.", "Amtsdeutsch ist eine eigene Sprache: kalt, pr\xE4zise, ohne Gnade.", "Aber ich verstehe die Regel: Wer die Formulare beherrscht, beherrscht die Stadt."]], "questions": [{ "text": "Was fehlt dem Antrag?", "options": [{ "t": "Eine g\xFCltige Bescheinigung \xFCber die technische Kontrolle.", "ok": true }, { "t": "Ein Foto des Piloten.", "ok": false }, { "t": "Die Unterschrift des Kommandanten.", "ok": false }] }, { "text": "Was passiert, wenn die Bescheinigung nicht kommt?", "options": [{ "t": "Nichts.", "ok": false }, { "t": "Der Antrag wird abgelehnt.", "ok": true }, { "t": "Das Amt ruft an.", "ok": false }] }] }, { "id": 27, "level": "B1", "title": "DAS DATENBLATT", "theme": "ELEKTRONIK / TECHNIK", "focus": { "title": "Relativs\xE4tze + Partizip als Adjektiv", "en": "Relative clauses describe a noun and push the verb to the end: der Sensor, der die Temperatur misst. Participles work as adjectives: ein besch\xE4digter Sensor = a damaged sensor." }, "paragraphs": [["Bruno gibt mir ein Datenblatt.", "\xBBTemperatursensor TX-90.", "Lies das, dann verstehst du die Maschine besser.\xAB"], ["Ich lese: Der Sensor misst Temperaturen von minus 40 bis plus 125 Grad.", "Die Genauigkeit betr\xE4gt 0,5 Grad.", "Die Versorgungsspannung liegt zwischen 3 und 5 Volt."], ["Wichtig ist die Warnung: Wenn die Spannung 6 Volt \xFCberschreitet, wird der Sensor besch\xE4digt.", "Ein besch\xE4digter Sensor liefert falsche Werte \u2014 und falsche Werte sind gef\xE4hrlicher als keine Werte."], ["Jetzt verstehe ich den Fehler von Kapitel eins: Das lockere Kabel hat die Verbindung unterbrochen, und der Sensor hat Unsinn gemeldet."], ["Ein System ist nur so ehrlich wie sein schw\xE4chster Sensor."]], "questions": [{ "text": "Was passiert, wenn die Spannung 6 Volt \xFCberschreitet?", "options": [{ "t": "Der Sensor wird besch\xE4digt.", "ok": true }, { "t": "Der Sensor wird genauer.", "ok": false }, { "t": "Nichts passiert.", "ok": false }] }, { "text": "Warum sind falsche Werte gef\xE4hrlich?", "options": [{ "t": "Weil sie gef\xE4hrlicher sind als keine Werte.", "ok": true }, { "t": "Weil sie zu klein sind.", "ok": false }, { "t": "Weil das Datenblatt fehlt.", "ok": false }] }] }, { "id": 28, "level": "B1", "title": "DIE BELAGERUNG", "theme": "MITTELALTER / ERZ\xC4HLUNG", "focus": { "title": "Pr\xE4teritum starker Verben + dass", "en": "Written narration uses Pr\xE4teritum: griff an (attacked), floss (flowed), fiel (fell), floh (fled). 'dass' (that) introduces reported thoughts and sends the verb to the end." }, "paragraphs": [["Der Feind griff am Morgen an.", "Die Belagerungsmaschine rollte langsam zum Tor, das offen stand."], ["Die Soldaten des Feindes lachten, weil sie dachten, dass wir dumm waren.", "Sie liefen durch das Tor \u2014 direkt in die Falle."], ["Das hei\xDFe \xD6l floss von den Mauern.", "Wer nicht fiel, floh.", "Die Belagerungsmaschine brannte bis zum Abend."], ["Der Hauptmann sagte sp\xE4ter: \xBBEine offene T\xFCr macht mehr Angst als eine geschlossene \u2014 wenn der Gegner denkt.\xAB"], ["Wir verloren drei M\xE4nner.", "Der Feind verlor den Glauben.", "Das war wichtiger."]], "questions": [{ "text": "Warum lachten die Soldaten des Feindes?", "options": [{ "t": "Weil sie dachten, dass die Verteidiger dumm waren.", "ok": true }, { "t": "Weil das Wetter gut war.", "ok": false }, { "t": "Weil sie gewonnen hatten.", "ok": false }] }, { "text": "Was verlor der Feind?", "options": [{ "t": "Drei M\xE4nner.", "ok": false }, { "t": "Den Glauben.", "ok": true }, { "t": "Das \xD6l.", "ok": false }] }] }, { "id": 29, "level": "B1", "title": "DAS GESPR\xC4CH", "theme": "BEWERBUNG / KONJUNKTIV", "focus": { "title": "Konjunktiv II: w\xE4re, h\xE4tte, k\xF6nnte", "en": "Konjunktiv II = would/could/had: w\xE4re (would be), h\xE4tte (would have), k\xF6nnte (could). Essential for politeness and job interviews: Ich h\xE4tte gern diese Stelle. K\xF6nnten Sie \u2026?" }, "paragraphs": [["Nach dem Krieg suchte ich Arbeit.", "Die Firma Vesta-Technik suchte einen Techniker f\xFCr Klimasysteme."], ["Im Gespr\xE4ch fragte die Chefin: \xBBWarum sollten wir Sie nehmen?\xAB", "Ich antwortete: \xBBIch habe drei Jahre lang eine Kampfmaschine am Leben gehalten.", "Ihr Klimasystem w\xE4re dagegen Urlaub.\xAB"], ["Sie l\xE4chelte.", "\xBBUnd wenn ein Kunde unfreundlich w\xE4re?\xAB", "\u2014 \xBBDann bliebe ich freundlich.", "Ich h\xE4tte gern diese Stelle, aber ich brauche keinen Krieg mehr.\xAB"], ["\xBBK\xF6nnten Sie am Montag anfangen?\xAB, fragte sie."], ["Ich konnte."]], "questions": [{ "text": "Was f\xFCr einen Techniker sucht die Firma?", "options": [{ "t": "Einen Techniker f\xFCr Klimasysteme.", "ok": true }, { "t": "Einen Piloten.", "ok": false }, { "t": "Einen Koch.", "ok": false }] }, { "text": "Was w\xFCrde der Pilot machen, wenn ein Kunde unfreundlich w\xE4re?", "options": [{ "t": "Er bliebe freundlich.", "ok": true }, { "t": "Er w\xFCrde gehen.", "ok": false }, { "t": "Er w\xFCrde k\xE4mpfen.", "ok": false }] }] }, { "id": 30, "level": "B1", "title": "DIE MESSSTATION", "theme": "MIKROKLIMA / PASSIV", "focus": { "title": "Passiv im Messprotokoll", "en": "Measurement reports live in the passive: Es werden f\xFCnf Parameter erfasst. Die Werte werden gespeichert und ausgewertet. The doer disappears; the process remains." }, "paragraphs": [["In der neuen Wohnung baue ich eine kleine Messstation.", "Es werden f\xFCnf Parameter erfasst: Temperatur, Luftfeuchtigkeit, CO2, Druck und Staub.", "F\xFCnf Zahlen, die beschreiben, wie ein Raum wirklich lebt."], ["Die Sensoren werden an der Wand montiert, weit weg vom Fenster und von der Heizung.", "Ein Sensor, der in der Sonne h\xE4ngt, misst nicht das Zimmer \u2014 er misst die Sonne.", "Die Position ist die halbe Messung."], ["Alle zehn Sekunden werden die Werte gelesen und gespeichert.", "Nachts wird gel\xFCftet, das sieht man sofort: Das CO2 f\xE4llt, die Temperatur auch.", "Daten l\xFCgen selten. Menschen interpretieren falsch."], ["Nach einer Woche wird das erste Muster sichtbar.", "Wenn ich koche, steigt die Feuchtigkeit um f\xFCnfzehn Prozent.", "Wenn Bruno zu Besuch ist, steigt das CO2 doppelt so schnell. Er redet viel."], ["Ein Raum ist auch nur ein System.", "Er hat Eing\xE4nge, Ausg\xE4nge und einen Zustand.", "Wer misst, der versteht. Wer versteht, der schl\xE4ft besser \u2014 bei genau einundzwanzig Grad."]], "questions": [{ "text": "Welche f\xFCnf Parameter werden erfasst?", "options": [{ "t": "Temperatur, Luftfeuchtigkeit, CO2, Druck und Staub.", "ok": true }, { "t": "Licht, L\xE4rm, Wind, Regen und Schnee.", "ok": false }, { "t": "Nur Temperatur und Druck.", "ok": false }] }, { "text": "Warum darf der Sensor nicht in der Sonne h\xE4ngen?", "options": [{ "t": "Er misst dann die Sonne, nicht das Zimmer.", "ok": true }, { "t": "Die Sonne macht ihn kaputt.", "ok": false }, { "t": "Das Kabel ist zu kurz.", "ok": false }] }] }, { "id": 31, "level": "B1", "title": "RAUM 214", "theme": "B\xDCROKRATIE / RELATIVS\xC4TZE", "focus": { "title": "Relativs\xE4tze im Amt", "en": "Bureaucracy describes everything with relative clauses: das Formular, das fehlt; die Frau, die entscheidet; der Stempel, den niemand hat. Verb at the end, patience in the middle." }, "paragraphs": [["Raum 214 ist der Raum, den jeder in Vesta kennt und den niemand mag.", "Hier sitzt die Frau, die \xFCber Ausweise entscheidet.", "Vor der T\xFCr warten Menschen, deren Geduld man messen k\xF6nnte \u2014 in Stunden."], ["Ich bringe die Unterlagen, die wir f\xFCr Kara gesammelt haben.", "Ein Zeuge, der Karas Familie kannte.", "Ein Foto, das ihre Mutter zeigt. Ein Brief, den ein Arzt geschrieben hat."], ["Die Frau pr\xFCft jedes Papier, das ich ihr gebe.", "Dann sagt sie den Satz, den ich schon kenne: \u201EEs fehlt der Nachweis, der die Evakuierung best\xE4tigt.\u201C", "Der Nachweis, den es nicht gibt, weil das Archiv, das ihn hatte, verbrannt ist."], ["Ich bleibe ruhig und stelle die Frage, die alles \xE4ndert:", "\u201EGibt es ein Verfahren f\xFCr F\xE4lle, in denen Dokumente durch Krieg verloren gingen?\u201C", "Sie schaut mich lange an. \u201EFormular 77-K\u201C, sagt sie. \u201EDas beantragt fast niemand, weil fast niemand danach fragt.\u201C"], ["Ich nehme das Formular, das niemand kennt.", "Manchmal ist das System eine Mauer.", "Und manchmal hat die Mauer ein Loch \u2014 man muss nur die richtige Frage stellen."]], "questions": [{ "text": "Welcher Nachweis fehlt?", "options": [{ "t": "Der Nachweis, der die Evakuierung best\xE4tigt.", "ok": true }, { "t": "Ein Foto von Bruno.", "ok": false }, { "t": "Der Pass des Piloten.", "ok": false }] }, { "text": "Warum beantragt fast niemand das Formular 77-K?", "options": [{ "t": "Weil fast niemand danach fragt.", "ok": true }, { "t": "Weil es zu teuer ist.", "ok": false }, { "t": "Weil Raum 214 geschlossen ist.", "ok": false }] }] }, { "id": 32, "level": "B1", "title": "DER TUNNEL", "theme": "STORY / PLUSQUAMPERFEKT", "focus": { "title": "Vorgeschichte mit hatte/war + Partizip", "en": "What happened before the story: Plusquamperfekt. Nachdem wir die Karte gefunden hatten, suchten wir den Eingang. Der Tunnel war lange vergessen worden." }, "paragraphs": [["Nachdem ich die Karte im Archiv gefunden hatte, lie\xDF mich der Gedanke nicht mehr los.", "Bruno und ich suchten den Eingang drei Wochenenden lang.", "Wir fanden ihn unter einer Platte, die jemand vor Jahrzehnten mit Beton verschlossen hatte."], ["Der Tunnel war enger, als die Karte versprochen hatte.", "Die Luft war kalt und roch nach Fluss.", "Unsere Lampen zeigten W\xE4nde, die seit hundert Jahren niemand gesehen hatte."], ["Nach vierhundert Metern fanden wir Spuren: eine Decke, Brotreste, eine Kinderlampe.", "Hier hatte jemand gelebt, nachdem alle die Zone verlassen hatten.", "Nicht Geister. Familien."], ["Am Ende des Tunnels war eine Leiter, die nach oben f\xFChrte \u2014 mitten in die Zone.", "Wir stiegen nicht hinauf.", "Manche T\xFCren \xF6ffnet man erst, wenn man wei\xDF, wer dahinter wartet."], ["Auf dem R\xFCckweg sagte Bruno leise: \u201EKara ist durch diesen Tunnel gekommen.\u201C", "Ich nickte.", "Die Stadt hatte die Zone vergessen. Aber die Zone hatte die Stadt nie vergessen."]], "questions": [{ "text": "Was fanden sie nach vierhundert Metern?", "options": [{ "t": "Eine Decke, Brotreste und eine Kinderlampe.", "ok": true }, { "t": "Hei\xDFes \xD6l und Pfeile.", "ok": false }, { "t": "Einen neuen Sensor.", "ok": false }] }, { "text": "Warum stiegen sie die Leiter nicht hinauf?", "options": [{ "t": "Man \xF6ffnet T\xFCren erst, wenn man wei\xDF, wer dahinter wartet.", "ok": true }, { "t": "Die Leiter war kaputt.", "ok": false }, { "t": "Die Lampen waren leer.", "ok": false }] }] }, { "id": 33, "level": "B1", "title": "DER ERSTE ARBEITSTAG", "theme": "ARBEIT / ZU-INFINITIV", "focus": { "title": "zu + Infinitiv im Berufsalltag", "en": "Work German loves zu-infinitives: Ich habe angefangen zu arbeiten. Es ist wichtig, p\xFCnktlich zu sein. Vergiss nicht, den Bericht abzugeben \u2014 separable verbs take zu inside: abzugeben." }, "paragraphs": [["Montag, acht Uhr: mein erster Arbeitstag bei Vesta-Technik.", "Ich versuche, ruhig zu wirken, und schaffe es fast.", "Die Chefin bittet mich, zuerst die Werkstatt kennenzulernen."], ["Mein Kollege Jonas zeigt mir alles.", "\u201EEs ist wichtig, jeden Auftrag zu dokumentieren\u201C, sagt er.", "\u201EUnd vergiss nicht, die Messger\xE4te am Abend auszuschalten. Der Chef hasst leere Batterien.\u201C"], ["Der erste Auftrag: eine Klimaanlage, die aufgeh\xF6rt hat zu k\xFChlen.", "Ich beginne, die \xFCblichen Verd\xE4chtigen zu pr\xFCfen: Filter, Sensor, Sicherung.", "Der Filter ist so voll, dass er vergessen hat, ein Filter zu sein."], ["Nach einer Stunde l\xE4uft die Anlage wieder.", "Die Kundin freut sich, uns Kaffee anzubieten.", "Jonas lehnt ab: \u201EWir haben noch vier Auftr\xE4ge zu erledigen.\u201C Ich lerne: Freundlich sein, aber weiterarbeiten."], ["Am Abend f\xFClle ich meinen ersten Bericht aus.", "Es f\xFChlt sich gut an, wieder gebraucht zu werden \u2014 ohne Krieg, ohne Reaktor.", "Nur eine Anlage, die wieder k\xFChlt, und ein Tag, der sich richtig anf\xFChlt."]], "questions": [{ "text": "Was soll der Pilot am Abend nicht vergessen?", "options": [{ "t": "Die Messger\xE4te auszuschalten.", "ok": true }, { "t": "Kaffee zu trinken.", "ok": false }, { "t": "Die Chefin anzurufen.", "ok": false }] }, { "text": "Warum lehnt Jonas den Kaffee ab?", "options": [{ "t": "Sie haben noch vier Auftr\xE4ge zu erledigen.", "ok": true }, { "t": "Er trinkt keinen Kaffee.", "ok": false }, { "t": "Der Kaffee ist zu teuer.", "ok": false }] }] }, { "id": 34, "level": "B1", "title": "KARAS SPUR", "theme": "STORY / INDIREKTE FRAGEN", "focus": { "title": "Indirekte Fragen", "en": "Careful questions go indirect \u2014 verb to the end: Ich wei\xDF nicht, wo ihre Familie ist. K\xF6nnen Sie mir sagen, ob es Listen gibt? 'ob' turns yes/no questions into clauses." }, "paragraphs": [["Formular 77-K verlangt Angaben, die Kara nicht kennt.", "Sie wei\xDF nicht, wann ihre Familie evakuiert wurde.", "Sie wei\xDF nur noch, dass es Winter war und dass die Lampen der Lastwagen blau waren."], ["Ich frage im Archiv, ob es Evakuierungslisten gibt.", "Der Archivar erkl\xE4rt mir, wo die alten Transportpl\xE4ne liegen.", "\u201ENiemand wei\xDF, ob sie vollst\xE4ndig sind\u201C, warnt er. \u201EAber blaue Lampen \u2014 das waren die Sanit\xE4tstransporte.\u201C"], ["Wir finden einen Plan vom Winter vor neun Jahren.", "Drei Sanit\xE4tstransporte, ein Ziel: das Lager im Osten.", "Ich frage mich, ob Karas Mutter dort registriert wurde."], ["Ich schreibe an das Lager und frage h\xF6flich, ob man mir sagen kann, wer damals angekommen ist.", "Die Antwort dauert drei Wochen.", "Dann liegt ein Brief im Kasten, bei dem meine H\xE4nde zittern."], ["\u201ESehr geehrter Herr, zu Ihrer Anfrage teilen wir mit: Eine Familie mit dem gesuchten Namen wurde am 12. Januar registriert.\u201C", "Ich lese den Satz dreimal.", "Dann laufe ich los, um Kara zu suchen \u2014 und wei\xDF zum ersten Mal genau, was ich ihr sagen werde."]], "questions": [{ "text": "Woran erinnert sich Kara?", "options": [{ "t": "Es war Winter und die Lampen der Lastwagen waren blau.", "ok": true }, { "t": "An die Adresse des Lagers.", "ok": false }, { "t": "An das Datum der Evakuierung.", "ok": false }] }, { "text": "Was bedeuteten blaue Lampen?", "options": [{ "t": "Sanit\xE4tstransporte.", "ok": true }, { "t": "Milit\xE4rtransporte.", "ok": false }, { "t": "Brottransporte.", "ok": false }] }] }, { "id": 35, "level": "B2", "title": "DER FEHLERBERICHT", "theme": "TECHNIK / NOMINALSTIL", "focus": { "title": "Nominalstil + Passiv Perfekt", "en": "Professional reports turn verbs into nouns: \xFCberhitzen \u2192 die \xDCberhitzung, unterbrechen \u2192 die Unterbrechung. Passive perfect: wurde festgestellt (was identified), konnte verhindert werden (could be prevented)." }, "paragraphs": [["Fehlerbericht Nr. 44, System ERIS-7.", "Verfasser: B. Weber, Techniker."], ["Zusammenfassung: Bei der Routinekontrolle wurde eine \xDCberhitzung des Reaktors festgestellt.", "Als Ursache wurde ein lockerer Steckverbinder identifiziert, der zu einer Unterbrechung der Sensorleitung f\xFChrte."], ["Infolge der fehlenden Temperaturdaten schaltete die Steuerung nicht in den K\xFChlmodus.", "Eine Besch\xE4digung des Reaktorkerns konnte durch das rechtzeitige Eingreifen des Piloten verhindert werden."], ["Ma\xDFnahmen: S\xE4mtliche Steckverbinder wurden ersetzt.", "Zus\xE4tzlich wurde eine redundante Messleitung installiert.", "Eine Wiederholung des Fehlers gilt als unwahrscheinlich."], ["Anmerkung des Verfassers: Maschinen versagen selten ohne Grund.", "Meistens haben Menschen den Grund montiert."]], "questions": [{ "text": "Was wurde als Ursache identifiziert?", "options": [{ "t": "Ein lockerer Steckverbinder.", "ok": true }, { "t": "Ein alter Reaktor.", "ok": false }, { "t": "Ein Fehler des Piloten.", "ok": false }] }, { "text": "Warum schaltete die Steuerung nicht in den K\xFChlmodus?", "options": [{ "t": "Weil die Temperaturdaten fehlten.", "ok": true }, { "t": "Weil der Strom ausfiel.", "ok": false }, { "t": "Weil der Modus verboten war.", "ok": false }] }] }, { "id": 36, "level": "B2", "title": "DER WIDERSPRUCH", "theme": "B\xDCROKRATIE / FORMELL", "focus": { "title": "Formelle Briefe: hiermit, fristgerecht, stattgeben", "en": "Objection-letter formulas: hiermit lege ich Widerspruch ein (I hereby object), fristgerecht (within the deadline), einem Antrag stattgeben (to grant an application). These exact phrases open doors in Germany." }, "paragraphs": [["Das Amt lehnte meinen Antrag ab \u2014 wegen eines fehlenden Stempels.", "Ich schrieb einen Widerspruch:"], ["\xBBSehr geehrte Damen und Herren, hiermit lege ich Widerspruch gegen Ihren Bescheid vom 3. Mai ein.", "Die geforderte Bescheinigung wurde fristgerecht eingereicht, was durch die beigef\xFCgte Kopie belegt wird."], ["Ich bitte Sie daher, den Bescheid zu \xFCberpr\xFCfen und meinem Antrag stattzugeben.", "Sollte dies nicht m\xF6glich sein, bitte ich um eine schriftliche Begr\xFCndung.", "Mit freundlichen Gr\xFC\xDFen.\xAB"], ["Zwei Wochen sp\xE4ter kam die Antwort: Dem Widerspruch wurde stattgegeben."], ["Die st\xE4rkste Waffe in dieser Stadt ist ein h\xF6flicher, korrekter Brief."]], "questions": [{ "text": "Warum lehnte das Amt den Antrag ab?", "options": [{ "t": "Wegen eines fehlenden Stempels.", "ok": true }, { "t": "Wegen der falschen Adresse.", "ok": false }, { "t": "Wegen des Wetters.", "ok": false }] }, { "text": "Wie endete die Geschichte?", "options": [{ "t": "Dem Widerspruch wurde stattgegeben.", "ok": true }, { "t": "Der Antrag wurde wieder abgelehnt.", "ok": false }, { "t": "Es kam keine Antwort.", "ok": false }] }] }, { "id": 37, "level": "B2", "title": "DIE ENTSCHEIDUNG", "theme": "FINALE / PLUSQUAMPERFEKT", "focus": { "title": "Plusquamperfekt + Passiv der Vergangenheit", "en": "Plusquamperfekt = past before past: hatte gelernt (had learned). Past passive perfect: war evakuiert worden (had been evacuated). The most complex standard German tense construction \u2014 if you read this chapter comfortably, you are at B2." }, "paragraphs": [["Am Ende fand ich die Wahrheit \xFCber die Zone heraus: Dort lebte niemand \u2014 au\xDFer denen, die die Stadt vergessen wollte."], ["Das M\xE4dchen hie\xDF Kara.", "Ihre Familie war vor Jahren evakuiert worden, jedoch ohne Papiere.", "Ohne Papiere existierte sie offiziell nicht; und wer nicht existiert, darf nicht durch das Tor."], ["Ich kannte inzwischen beide Welten: die der Maschinen, die ehrlich versagen, und die der Formulare, die Menschen verschwinden lassen."], ["Also tat ich, was ich gelernt hatte: Ich f\xFCllte Formulare aus.", "Antrag f\xFCr Antrag, Widerspruch f\xFCr Widerspruch, bis Kara eines Tages einen Pass in der Hand hielt."], ["Manche Schlachten gewinnt man mit hei\xDFem \xD6l.", "Die wichtigsten gewinnt man mit Geduld und einem Kugelschreiber."]], "questions": [{ "text": "Warum existierte Kara offiziell nicht?", "options": [{ "t": "Weil ihre Familie ohne Papiere evakuiert worden war.", "ok": true }, { "t": "Weil sie ein Geist war.", "ok": false }, { "t": "Weil sie nie geboren wurde.", "ok": false }] }, { "text": "Wie half der Pilot Kara?", "options": [{ "t": "Er f\xFCllte Formulare aus, bis sie einen Pass bekam.", "ok": true }, { "t": "Er k\xE4mpfte gegen das Amt.", "ok": false }, { "t": "Er flog sie \xFCber die Mauer.", "ok": false }] }] }, { "id": 38, "level": "B2", "title": "DER PR\xDCFBERICHT", "theme": "TECHNIK / NOMINALSTIL", "focus": { "title": "Nominalstil im Pr\xFCfbericht", "en": "Professional reports turn actions into nouns: die Inbetriebnahme, die Kalibrierung, die Abweichung. Passive plus nouns = maximum distance, maximum authority." }, "paragraphs": [["Pr\xFCfbericht: Inbetriebnahme der Messstation, f\xFCnf Parameter. Pr\xFCfer: der Bewohner selbst \u2014 Objektivit\xE4t daher eingeschr\xE4nkt, Sorgfalt daf\xFCr maximal.", "Gegenstand der Pr\xFCfung war die \xDCbereinstimmung der Messwerte mit zwei Referenzger\xE4ten.", "Die Pr\xFCfung erfolgte \xFCber einen Zeitraum von sieben Tagen."], ["Ergebnis der Temperaturmessung: mittlere Abweichung 0,2 Grad; nach erfolgter Kalibrierung 0,1 Grad.", "Die Feuchtigkeitsmessung zeigte eine systematische Abweichung von drei Prozent, verursacht durch die N\xE4he zur K\xFCche.", "Nach Versetzung des Sensors wurde die Abweichung auf ein Prozent reduziert."], ["Bei der CO2-Messung wurde eine Auff\xE4lligkeit festgestellt: n\xE4chtliche Spitzenwerte trotz L\xFCftung.", "Als Ursache wurde die Schlafzimmert\xFCr identifiziert, deren Schlie\xDFung die Luftzirkulation unterbindet.", "Empfehlung: T\xFCr ge\xF6ffnet lassen oder mit dem Schnarchen des Bewohners leben \u2014 die Messtechnik ist hier machtlos."], ["Die Druck- und Staubmessung verlief ohne Beanstandung.", "Ein Anstieg der Staubwerte am Dienstag korrelierte mit dem Besuch eines Technikers samt Transporter.", "Von einer Reklamation wurde abgesehen; der Techniker brachte Kartoffeln."], ["Gesamtbewertung: Die Station ist betriebsbereit.", "Die Dokumentation der Ergebnisse erfolgt fortlaufend.", "Anmerkung des Pr\xFCfers: Wer seine Luft kennt, kennt sein Leben. Der Rest ist Interpretation."]], "questions": [{ "text": "Wodurch wurde die Abweichung der Feuchtigkeitsmessung verursacht?", "options": [{ "t": "Durch die N\xE4he zur K\xFCche.", "ok": true }, { "t": "Durch das Schnarchen.", "ok": false }, { "t": "Durch den Transporter.", "ok": false }] }, { "text": "Warum wurde von einer Reklamation abgesehen?", "options": [{ "t": "Der Techniker brachte Kartoffeln.", "ok": true }, { "t": "Die Werte waren perfekt.", "ok": false }, { "t": "Das Formular fehlte.", "ok": false }] }] }, { "id": 39, "level": "B2", "title": "DIE ANH\xD6RUNG", "theme": "AMT / KONJUNKTIV I", "focus": { "title": "Konjunktiv I: Protokollsprache", "en": "Hearings are recorded in reported speech: Der Zeuge erkl\xE4rte, die Familie sei registriert worden. Sie habe den Transport gesehen. Konjunktiv I marks: reported, not verified." }, "paragraphs": [["Die Anh\xF6rung zu Karas Antrag fand an einem Dienstag statt.", "Ein Beamter f\xFChrte das Protokoll, eine Beamtin stellte die Fragen.", "Kara sa\xDF sehr gerade, wie jemand, der gelernt hat, dass Sitzen auch eine Pr\xFCfung sein kann."], ["Im Protokoll steht sp\xE4ter: Der Antragstellerin zufolge sei ihre Familie im Winter evakuiert worden.", "Sie habe die blauen Lampen der Fahrzeuge gesehen und sei bei der Abfahrt zur\xFCckgeblieben.", "Ein Nachweis des Aufnahmelagers liege vor und best\xE4tige die Registrierung der Familie."], ["Der Archivar sagte als Zeuge aus.", "Er erkl\xE4rte, die Evakuierungslisten seien unvollst\xE4ndig, das Fehlen eines Namens beweise daher nichts.", "Die Beamtin nickte langsam \u2014 das Nicken einer Frau, die schon viele unvollst\xE4ndige Listen gesehen hat."], ["Dann fragte sie Kara direkt: \u201EWas w\xFCnschst du dir von diesem Amt?\u201C", "Kara antwortete: \u201EDass ich existiere. Auf Papier. Wie alle anderen.\u201C", "Der Protokollf\xFChrer h\xF6rte f\xFCr zwei Sekunden auf zu tippen."], ["Die Entscheidung, hie\xDF es, werde schriftlich zugestellt.", "Wir gingen schweigend zum Bus.", "Manche S\xE4tze kann kein Konjunktiv distanzieren."]], "questions": [{ "text": "Was best\xE4tigt der Nachweis des Aufnahmelagers?", "options": [{ "t": "Die Registrierung der Familie.", "ok": true }, { "t": "Die Farbe der Lampen.", "ok": false }, { "t": "Das Alter des Archivars.", "ok": false }] }, { "text": "Was erkl\xE4rte der Archivar \xFCber die Listen?", "options": [{ "t": "Sie seien unvollst\xE4ndig; ein fehlender Name beweise nichts.", "ok": true }, { "t": "Sie seien vollst\xE4ndig und korrekt.", "ok": false }, { "t": "Sie seien verbrannt und wertlos.", "ok": false }] }] }, { "id": 40, "level": "B2", "title": "EPILOG: ZWEI WELTEN", "theme": "FINALE / MODALPARTIKELN", "focus": { "title": "Je\u2026desto und vermutende Modalverben", "en": "The finale weaves B2 threads: je\u2026desto for proportions, d\xFCrfte/m\xFCsste for measured guesses. Je l\xE4nger man bleibt, desto mehr versteht man \u2014 das d\xFCrfte f\xFCr St\xE4dte wie f\xFCr Menschen gelten." }, "paragraphs": [["Ein Jahr sp\xE4ter steht ERIS-7 im Museum von Vesta.", "Kinder klettern auf ihre F\xFC\xDFe; ein Schild bittet h\xF6flich, es zu unterlassen. Niemand h\xE4lt sich daran.", "Maschinen, die niemand mehr f\xFCrchtet, d\xFCrften die gl\xFCcklichsten Maschinen sein."], ["Die Zone hat jetzt ein Tor, das tags\xFCber offen steht.", "Je mehr Menschen hindurchgehen, desto kleiner wird das Wort \u201EZone\u201C.", "Bald sagt man wohl wieder einfach: der alte Stadtteil am Fluss."], ["Kara geht zur Schule und streitet mit Bruno \xFCber die richtige Temperatur f\xFCr Kartoffeln.", "Sie behauptet, hundertneunzig Grad seien besser als zweihundert.", "Bruno will das nicht gelten lassen \u2014 aber er probiert es heimlich aus. Sie d\xFCrfte recht haben."], ["Ich arbeite bei Vesta-Technik und messe die Luft fremder Wohnungen.", "Je genauer ich messe, desto \xF6fter denke ich: Ein Haus ist ehrlich wie eine Maschine \u2014 man muss nur die richtigen Sensoren haben.", "Bei Menschen m\xFCsste man dasselbe sagen k\xF6nnen. Die Sensoren hei\xDFen dort Fragen."], ["Abends sitze ich manchmal am Fluss, wo der Tunnel endet.", "Zwei Welten hatte ich kennengelernt: die der Maschinen und die der Formulare.", "Gewonnen haben wir in beiden \u2014 mit Geduld, einem Kugelschreiber und ein wenig hei\xDFem \xD6l. Aber das \xD6l, das sei zugegeben, war lange vorher."]], "questions": [{ "text": "Wo steht ERIS-7 ein Jahr sp\xE4ter?", "options": [{ "t": "Im Museum von Vesta.", "ok": true }, { "t": "Im Hangar.", "ok": false }, { "t": "In der Zone.", "ok": false }] }, { "text": "Wor\xFCber streiten Kara und Bruno?", "options": [{ "t": "\xDCber die richtige Temperatur f\xFCr Kartoffeln.", "ok": true }, { "t": "\xDCber die Schule.", "ok": false }, { "t": "\xDCber die Sensoren.", "ok": false }] }] }];
